import{_ as t,o,c as a,a2 as r}from"./chunks/framework.ChXBHUFc.js";const m=JSON.parse('{"title":"BLE protocol","description":"","frontmatter":{},"headers":[],"relativePath":"guide/ble-protocol.md","filePath":"guide/ble-protocol.md","lastUpdated":1782601617000}'),d={name:"guide/ble-protocol.md"};function s(c,e,n,i,l,p){return o(),a("div",null,[...e[0]||(e[0]=[r(`<h1 id="ble-protocol" tabindex="-1">BLE protocol <a class="header-anchor" href="#ble-protocol" aria-label="Permalink to &quot;BLE protocol&quot;">​</a></h1><p>Notes on the Triki BLE interface, captured with <a href="./tooling">bleak</a> on macOS.</p><blockquote><p><strong>OPSEC:</strong> device-identifying values (chip ID, any per-device value) are NOT recorded here — only structure is kept.</p></blockquote><h2 id="advertising" tabindex="-1">Advertising <a class="header-anchor" href="#advertising" aria-label="Permalink to &quot;Advertising&quot;">​</a></h2><p>Name <code>TRIKI &lt;serial&gt;</code> / <code>Triki &lt;serial&gt;</code>, address <code>XX:XX:XX:XX:XX:XX</code> (random static), service <code>0x0001</code>.</p><h2 id="gatt" tabindex="-1">GATT <a class="header-anchor" href="#gatt" aria-label="Permalink to &quot;GATT&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Nordic UART Service  6e400001-b5a3-f393-e0a9-e50e24dcca9e</span></span>
<span class="line"><span>  RX   …0002  [write, write-no-response]   commands host -&gt; token</span></span>
<span class="line"><span>  TX   …0003  [notify]                     responses token -&gt; host</span></span>
<span class="line"><span>  ctrl …0004  [read, write]                control register</span></span>
<span class="line"><span>Battery 0x180F → 0x2A19 (Battery Level)</span></span></code></pre></div><p>The token speaks a <strong>request/response protocol over NUS</strong>: TX stays silent until a command arrives on RX.</p><h2 id="control-register-0x0004-—-green-led" tabindex="-1">Control register 0x0004 — green LED <a class="header-anchor" href="#control-register-0x0004-—-green-led" aria-label="Permalink to &quot;Control register 0x0004 — green LED&quot;">​</a></h2><ul><li><strong>1-bit flag.</strong> Writes saturate: <code>0x00</code> → reads back <code>0x00</code>; any value <code>&gt;= 0x01</code> → reads back <code>0x01</code>. Effective search space = 2 states.</li><li><strong>Bit0 directly drives the green LED</strong>: <code>0x01</code> = green on, <code>0x00</code> = off — immediate, no timeout (confirmed visually).</li></ul><h2 id="rx-0x0002-—-command-interface" tabindex="-1">RX 0x0002 — command interface <a class="header-anchor" href="#rx-0x0002-—-command-interface" aria-label="Permalink to &quot;RX 0x0002 — command interface&quot;">​</a></h2><ul><li>Commands are <strong>byte sequences</strong> (byte0 = opcode). Some are single-byte, some are multi-byte (e.g. the 8-byte IMU start command — see <a href="./imu-streaming">IMU streaming</a>).</li><li><strong>Response opcode = request opcode | 0x80</strong> (bit7 set = &quot;this is a reply&quot;), delivered on TX as one or more 20-byte notification packets.</li><li>A few opcodes reboot the device (short LED blink, link drops, comes back as the same device — a soft reset).</li></ul><h3 id="opcode-map-rx-→-tx-so-far" tabindex="-1">Opcode map (RX → TX), so far <a class="header-anchor" href="#opcode-map-rx-→-tx-so-far" aria-label="Permalink to &quot;Opcode map (RX → TX), so far&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Opcode</th><th>Reply</th><th>Meaning / notes</th></tr></thead><tbody><tr><td><code>0x05</code></td><td><code>85</code> + 12 bytes</td><td><strong>static</strong> config/status — does NOT change with motion</td></tr><tr><td><code>0x07</code></td><td><code>87</code> + 8 bytes</td><td>device unique ID — stable across reads; value redacted</td></tr><tr><td><code>0x09</code></td><td><code>89</code> + ~54 bytes (multi-packet)</td><td>status block — counter + state fields; NOT motion data</td></tr><tr><td><code>0x0c</code></td><td><code>8c 01 00 00 00</code></td><td>short status/counter</td></tr><tr><td><code>0x43</code></td><td><code>c3</code> + ~54 bytes</td><td>changes every read → live buffer/counter; value redacted</td></tr><tr><td><code>0x0a</code>, <code>0x42</code>, <code>0x44</code>, <code>0x46</code></td><td>—</td><td>reboot (soft reset)</td></tr><tr><td>all other <code>0x00</code>–<code>0x7f</code></td><td>—</td><td>silent (no single-byte reply; likely need parameters)</td></tr></tbody></table><p>The raw IMU is <strong>not</strong> on these single-byte opcodes — it comes from the dedicated start-stream command on the <a href="./imu-streaming">IMU streaming</a> page.</p>`,15)])])}const g=t(d,[["render",s]]);export{m as __pageData,g as default};
